var CustomerCmd = func() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "customer [CUSTOMER_ID]",
		Short: "Advance invoices for a customer",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			if namespace == "" {
				return fmt.Errorf("namespace is required")
			}
			_, err := internal.App.BillingAutoAdvancer.AdvanceInvoice(cmd.Context(), billing.InvoiceID{
				Namespace: namespace,
				ID:        args[0],
			})
			return err
		},
	}
	return cmd
}

var NewCmd = func() *cobra.Command {
	cmd := &cobra.Command{
		Use:  "new-op",
		RunE: func(cmd *cobra.Command, args []string) error {
			if internal.App.ChargesAutoAdvancer == nil {
				return fmt.Errorf("charges are not enabled")
			}
			if namespace == "" {
				return fmt.Errorf("namespace is required")
			}
			return internal.App.ChargesAutoAdvancer.AdvanceCharges(cmd.Context(), customer.CustomerID{
				Namespace: namespace,
				ID:        args[0],
			})
		},
	}
	return cmd
}

var ByCustomerCmd = func() *cobra.Command {
	var ns, cids []string
	cmd := &cobra.Command{
		Use:  "by-customer",
		RunE: func(cmd *cobra.Command, args []string) error {
			return internal.App.BillingCollector.All(cmd.Context(), ns, cids, 0)
		},
	}
	cmd.PersistentFlags().StringSliceVar(&ns, "n", nil, "filter by namespaces")
	cmd.PersistentFlags().StringSliceVar(&cids, "c", nil, "filter by customer ids")
	return cmd
}

var DryRunCmd = func() *cobra.Command {
	var ns, cids []string
	var lb time.Duration
	cmd := &cobra.Command{
		Use:  "dryrun",
		RunE: func(cmd *cobra.Command, args []string) error {
			subs, err := internal.App.BillingSubscriptionReconciler.ListSubscriptions(
				cmd.Context(),
				reconciler.ReconcilerListSubscriptionsInput{
					Namespaces: ns,
					Customers:  cids,
					Lookback:   lb,
				})
			if err != nil {
				return err
			}
			fmt.Printf("%d subscriptions would be synced\n", len(subs))
			return nil
		},
	}
	cmd.PersistentFlags().StringSliceVar(&ns, "n", nil, "filter by namespaces")
	cmd.PersistentFlags().StringSliceVar(&cids, "c", nil, "filter by customer ids")
	cmd.PersistentFlags().DurationVar(&lb, "l", defaultLookback, "lookback period")
	return cmd
}
